DROP TABLE IF EXISTS volunteers CASCADE;
DROP TABLE IF EXISTS skills CASCADE;
DROP TABLE IF EXISTS events CASCADE;

-- A volunteer event — festival, food bank shift block, conference, etc.
CREATE TABLE events (
  id SERIAL PRIMARY KEY,
  name TEXT NOT NULL,
  location TEXT NOT NULL DEFAULT '',
  event_date DATE NOT NULL,
  target_hours_per_volunteer NUMERIC(5,2) NOT NULL DEFAULT 4
);

-- A discrete capability a volunteer can hold (e.g. First Aid).
CREATE TABLE skills (
  id SERIAL PRIMARY KEY,
  name TEXT NOT NULL UNIQUE
);

-- A person who can be assigned to shifts.
CREATE TABLE volunteers (
  id SERIAL PRIMARY KEY,
  name TEXT NOT NULL,
  email TEXT NOT NULL UNIQUE,
  reliability_score NUMERIC(3,2) NOT NULL DEFAULT 0.85 CHECK (reliability_score BETWEEN 0 AND 1),
  max_hours NUMERIC(5,2) NOT NULL DEFAULT 8
);

-- Many-to-many: which volunteers hold which skills.
CREATE TABLE volunteer_skills (
  volunteer_id INTEGER NOT NULL REFERENCES volunteers(id) ON DELETE CASCADE,
  skill_id INTEGER NOT NULL REFERENCES skills(id) ON DELETE CASCADE,
  PRIMARY KEY (volunteer_id, skill_id)
);

-- A time block within an event that needs `required_count` volunteers.
CREATE TABLE shifts (
  id SERIAL PRIMARY KEY,
  event_id INTEGER NOT NULL REFERENCES events(id) ON DELETE CASCADE,
  name TEXT NOT NULL,
  starts_at TIMESTAMP NOT NULL,
  ends_at TIMESTAMP NOT NULL,
  required_count INTEGER NOT NULL DEFAULT 1 CHECK (required_count >= 0),
  required_skill_id INTEGER REFERENCES skills(id) ON DELETE SET NULL
);

-- Pins a volunteer to a shift. (shift_id, volunteer_id) is unique.
CREATE TABLE assignments (
  id SERIAL PRIMARY KEY,
  shift_id INTEGER NOT NULL REFERENCES shifts(id) ON DELETE CASCADE,
  volunteer_id INTEGER NOT NULL REFERENCES volunteers(id) ON DELETE CASCADE,
  created_at TIMESTAMP NOT NULL DEFAULT NOW(),
  UNIQUE (shift_id, volunteer_id)
);

CREATE INDEX ix_shifts_event ON shifts(event_id);
CREATE INDEX ix_assignments_shift ON assignments(shift_id);
CREATE INDEX ix_assignments_volunteer ON assignments(volunteer_id);
